//! # Reader — bytes → `Rknot`
//!
//! Inverse of `writer.rs`. Two-phase API: [`read_rknot_header`] for cheap
//! header-only loads (caller can then `seek_to_body` and pull individual
//! blocks via [`read_block_payload`]), [`read_rknot_from_file`] for the
//! convenience all-in-one path.
//!
//! ## Binary layout (RKNOT_v2, mirrors `format.rs`)
//!
//! ```text
//! magic        :  6 bytes  "RKNOT\x02"
//! header_len   :  4 bytes  u32 LE
//! header_json  :  N bytes
//! body         :  rest     concat of QuantBlock.payload bytes,
//!                          indexed by per-block body_offset in header
//! ```
//!
//! Body origin (the first byte after the JSON header) is at
//! `6 + 4 + header_len` from start of file.

use std::fs::File;
use std::io::{self, Read, Seek, SeekFrom};

use super::format::*;

/// Errors emitted during reading.
#[derive(Debug)]
pub enum ReadError {
    Io(io::Error),
    Serde(serde_json::Error),
    BadMagic { found: [u8; 6] },
    HeaderTooLong { len: u32, file_size: u64 },
    BodyOffsetOutOfBounds { layer_idx: u32, offset: u64 },
}

impl From<io::Error> for ReadError {
    fn from(e: io::Error) -> Self {
        ReadError::Io(e)
    }
}

impl From<serde_json::Error> for ReadError {
    fn from(e: serde_json::Error) -> Self {
        ReadError::Serde(e)
    }
}

impl std::fmt::Display for ReadError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ReadError::Io(e) => write!(f, "io error: {}", e),
            ReadError::Serde(e) => write!(f, "serde error: {}", e),
            ReadError::BadMagic { found } => {
                write!(
                    f,
                    "bad magic bytes: {:?} (expected {:?})",
                    found, RKNOT_MAGIC
                )
            }
            ReadError::HeaderTooLong { len, file_size } => {
                write!(f, "header_len {} exceeds file size {}", len, file_size)
            }
            ReadError::BodyOffsetOutOfBounds { layer_idx, offset } => write!(
                f,
                "body offset {} out of bounds for layer {}",
                offset, layer_idx
            ),
        }
    }
}

impl std::error::Error for ReadError {}

/// Body-origin byte offset given the JSON header length. The body
/// region starts immediately after `magic (6) || header_len (4) ||
/// header_json (header_len)`.
#[inline]
pub fn body_origin(header_len: u32) -> u64 {
    6 + 4 + header_len as u64
}

/// Read just the JSON header from a `.rknot` reader. Body is left
/// unread — caller can `seek_to_body` for selective block loads.
///
/// Reads `magic (6) || header_len (u32 LE, 4) || header_json (header_len)`.
pub fn read_rknot_header<R: Read>(r: &mut R) -> Result<RknotHeader, ReadError> {
    // Magic.
    let mut magic = [0u8; 6];
    r.read_exact(&mut magic)?;
    if &magic != RKNOT_MAGIC {
        return Err(ReadError::BadMagic { found: magic });
    }

    // Header length (u32 LE).
    let mut hlen_buf = [0u8; 4];
    r.read_exact(&mut hlen_buf)?;
    let header_len = u32::from_le_bytes(hlen_buf);

    // Header JSON.
    let mut header_bytes = vec![0u8; header_len as usize];
    r.read_exact(&mut header_bytes)?;
    let header: RknotHeader = serde_json::from_slice(&header_bytes)?;
    Ok(header)
}

/// Read a single block payload from the body using the reference's
/// byte offset and length. Caller is responsible for the `body_origin`
/// pointing at the start of the body region (i.e. `6 + 4 + header_len`).
pub fn read_block_payload<R: Read + Seek>(
    r: &mut R,
    body_origin: u64,
    block_ref: &RknotBlockRef,
) -> Result<Vec<u8>, ReadError> {
    let abs = body_origin
        .checked_add(block_ref.body_offset)
        .ok_or(ReadError::BodyOffsetOutOfBounds {
            layer_idx: u32::MAX,
            offset: block_ref.body_offset,
        })?;
    r.seek(SeekFrom::Start(abs))?;
    let mut payload = vec![0u8; block_ref.payload_byte_len as usize];
    r.read_exact(&mut payload)?;
    Ok(payload)
}

/// Read the entire `.rknot` file into an in-memory [`Rknot`]. For
/// large models prefer [`read_rknot_header`] + selective block loads
/// via [`read_block_payload`].
pub fn read_rknot_from_file(path: &std::path::Path) -> Result<Rknot, ReadError> {
    let file = File::open(path)?;
    let file_size = file.metadata()?.len();
    let mut reader = io::BufReader::new(file);

    // Magic.
    let mut magic = [0u8; 6];
    reader.read_exact(&mut magic)?;
    if &magic != RKNOT_MAGIC {
        return Err(ReadError::BadMagic { found: magic });
    }

    // Header length.
    let mut hlen_buf = [0u8; 4];
    reader.read_exact(&mut hlen_buf)?;
    let header_len = u32::from_le_bytes(hlen_buf);
    if (header_len as u64) + 6 + 4 > file_size {
        return Err(ReadError::HeaderTooLong {
            len: header_len,
            file_size,
        });
    }

    // Header JSON.
    let mut header_bytes = vec![0u8; header_len as usize];
    reader.read_exact(&mut header_bytes)?;
    let header: RknotHeader = serde_json::from_slice(&header_bytes)?;

    let origin = body_origin(header_len);

    // Walk the layers and pull each block payload.
    let mut layers: Vec<ResonanceKnotLayer> = Vec::with_capacity(header.layers.len());
    for layer_ref in &header.layers {
        let q_payload = read_one(
            &mut reader,
            origin,
            &layer_ref.q_ref,
            layer_ref.layer_idx,
            file_size,
        )?;
        let k_payload = read_one(
            &mut reader,
            origin,
            &layer_ref.k_ref,
            layer_ref.layer_idx,
            file_size,
        )?;
        let v_payload = read_one(
            &mut reader,
            origin,
            &layer_ref.v_ref,
            layer_ref.layer_idx,
            file_size,
        )?;
        let ffn_payload = read_one(
            &mut reader,
            origin,
            &layer_ref.ffn_ref,
            layer_ref.layer_idx,
            file_size,
        )?;

        layers.push(ResonanceKnotLayer {
            layer_idx: layer_ref.layer_idx,
            manifest: layer_ref.manifest.clone(),
            q_block: QuantBlock {
                rows: layer_ref.q_rows,
                cols: layer_ref.q_cols,
                bits_per_entry: layer_ref.q_bits_per_entry,
                payload: q_payload,
            },
            k_block: QuantBlock {
                rows: layer_ref.k_rows,
                cols: layer_ref.k_cols,
                bits_per_entry: layer_ref.k_bits_per_entry,
                payload: k_payload,
            },
            v_block: QuantBlock {
                rows: layer_ref.v_rows,
                cols: layer_ref.v_cols,
                bits_per_entry: layer_ref.v_bits_per_entry,
                payload: v_payload,
            },
            ffn_block: QuantBlock {
                rows: layer_ref.ffn_rows,
                cols: layer_ref.ffn_cols,
                bits_per_entry: layer_ref.ffn_bits_per_entry,
                payload: ffn_payload,
            },
        });
    }

    Ok(Rknot {
        arch_meta: header.arch_meta,
        layers,
        encoder_version: header.encoder_version,
        calibration_probe: header.calibration_probe,
        saturation_maps: header.saturation_maps,
    })
}

fn read_one<R: Read + Seek>(
    r: &mut R,
    origin: u64,
    block_ref: &RknotBlockRef,
    layer_idx: u32,
    file_size: u64,
) -> Result<Vec<u8>, ReadError> {
    let abs =
        origin
            .checked_add(block_ref.body_offset)
            .ok_or(ReadError::BodyOffsetOutOfBounds {
                layer_idx,
                offset: block_ref.body_offset,
            })?;
    if abs
        .checked_add(block_ref.payload_byte_len)
        .is_none_or(|end| end > file_size)
    {
        return Err(ReadError::BodyOffsetOutOfBounds {
            layer_idx,
            offset: block_ref.body_offset,
        });
    }
    r.seek(SeekFrom::Start(abs))?;
    let mut buf = vec![0u8; block_ref.payload_byte_len as usize];
    r.read_exact(&mut buf)?;
    Ok(buf)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Cursor;

    /// Build a synthetic in-memory `.rknot` byte stream with a single
    /// layer carrying four small payloads. Doesn't depend on
    /// `writer.rs` — mimics the on-disk layout described by `format.rs`.
    ///
    /// Returns `(bytes, header, payloads_in_order)` for round-trip
    /// assertions.
    fn build_synthetic_rknot() -> (Vec<u8>, RknotHeader, Vec<Vec<u8>>) {
        let q_payload = vec![0xAA, 0xBB, 0xCC, 0xDD];
        let k_payload = vec![0x11, 0x22, 0x33, 0x44];
        let v_payload = vec![0x55, 0x66, 0x77, 0x88, 0x99, 0x00];
        let ffn_payload = vec![0xDE, 0xAD, 0xBE, 0xEF, 0xCA, 0xFE, 0xBA, 0xBE];

        let mut body = Vec::new();
        let q_off = body.len() as u64;
        body.extend_from_slice(&q_payload);
        let k_off = body.len() as u64;
        body.extend_from_slice(&k_payload);
        let v_off = body.len() as u64;
        body.extend_from_slice(&v_payload);
        let ffn_off = body.len() as u64;
        body.extend_from_slice(&ffn_payload);

        let manifest = SpectralManifest {
            d: 8,
            k: 2,
            standing_indices: vec![0, 4],
            amplitudes: vec![0.5, 0.6],
            phase_alignment: vec![0.7, 0.8],
        };

        let header = RknotHeader {
            arch_meta: ArchMeta {
                arch: "test".to_string(),
                hidden_dim: 8,
                num_layers: 1,
                num_heads: 2,
                num_kv_heads: 2,
                head_dim: 4,
                intermediate_size: 16,
                vocab_size: 32,
                rms_norm_eps: 1e-5,
                rope_theta: 10000.0,
            },
            layers: vec![RknotLayerRef {
                layer_idx: 0,
                manifest: manifest.clone(),
                q_ref: RknotBlockRef {
                    body_offset: q_off,
                    payload_byte_len: q_payload.len() as u64,
                },
                q_bits_per_entry: 4,
                q_rows: 2,
                q_cols: 2,
                k_ref: RknotBlockRef {
                    body_offset: k_off,
                    payload_byte_len: k_payload.len() as u64,
                },
                k_bits_per_entry: 4,
                k_rows: 2,
                k_cols: 2,
                v_ref: RknotBlockRef {
                    body_offset: v_off,
                    payload_byte_len: v_payload.len() as u64,
                },
                v_bits_per_entry: 8,
                v_rows: 2,
                v_cols: 3,
                ffn_ref: RknotBlockRef {
                    body_offset: ffn_off,
                    payload_byte_len: ffn_payload.len() as u64,
                },
                ffn_bits_per_entry: 4,
                ffn_rows: 2,
                ffn_cols: 16,
            }],
            encoder_version: "rknot-test/0.0.0".to_string(),
            calibration_probe: Some("synthetic".to_string()),
            saturation_maps: None,
        };

        let header_json = serde_json::to_vec(&header).expect("header serializes");
        let header_len = header_json.len() as u32;

        let mut bytes = Vec::new();
        bytes.extend_from_slice(RKNOT_MAGIC);
        bytes.extend_from_slice(&header_len.to_le_bytes());
        bytes.extend_from_slice(&header_json);
        bytes.extend_from_slice(&body);

        (
            bytes,
            header,
            vec![q_payload, k_payload, v_payload, ffn_payload],
        )
    }

    #[test]
    fn round_trip_synthetic_layer() {
        let (bytes, expected_header, payloads) = build_synthetic_rknot();

        // Header-only path.
        let mut header_cursor = Cursor::new(bytes.clone());
        let header = read_rknot_header(&mut header_cursor).expect("header reads");
        assert_eq!(header.arch_meta.arch, expected_header.arch_meta.arch);
        assert_eq!(header.layers.len(), 1);
        assert_eq!(header.encoder_version, "rknot-test/0.0.0");
        assert_eq!(header.calibration_probe.as_deref(), Some("synthetic"));

        // Selective block load.
        let mut cursor = Cursor::new(bytes.clone());
        // Need to know header_len to compute body origin — re-read.
        cursor.seek(SeekFrom::Start(6)).unwrap();
        let mut hlen_buf = [0u8; 4];
        cursor.read_exact(&mut hlen_buf).unwrap();
        let hlen = u32::from_le_bytes(hlen_buf);
        let origin = body_origin(hlen);

        let q_back = read_block_payload(&mut cursor, origin, &header.layers[0].q_ref).unwrap();
        assert_eq!(q_back, payloads[0], "Q payload round trips");

        let v_back = read_block_payload(&mut cursor, origin, &header.layers[0].v_ref).unwrap();
        assert_eq!(
            v_back, payloads[2],
            "V payload round trips (out-of-order seek)"
        );

        let ffn_back = read_block_payload(&mut cursor, origin, &header.layers[0].ffn_ref).unwrap();
        assert_eq!(ffn_back, payloads[3], "FFN payload round trips");
    }

    #[test]
    fn bad_magic_rejected() {
        let mut bytes = Vec::new();
        bytes.extend_from_slice(b"KNOT\x00\x00"); // wrong magic
        bytes.extend_from_slice(&0u32.to_le_bytes());
        let mut cursor = Cursor::new(bytes);
        match read_rknot_header(&mut cursor) {
            Err(ReadError::BadMagic { found }) => {
                assert_eq!(&found, b"KNOT\x00\x00");
            }
            other => panic!("expected BadMagic, got {:?}", other),
        }
    }

    #[test]
    fn header_too_long_rejected() {
        // Synthesize a file that claims a header_len far larger than the
        // file. Goes through `read_rknot_from_file` which checks file size.
        let tmp = std::env::temp_dir().join(format!(
            "rknot_reader_header_too_long_{}.bin",
            std::process::id()
        ));
        {
            use std::io::Write;
            let mut f = std::fs::File::create(&tmp).unwrap();
            f.write_all(RKNOT_MAGIC).unwrap();
            // Claim a header_len that is absurdly large.
            f.write_all(&0xFFFF_FFFFu32.to_le_bytes()).unwrap();
            // Body is empty — file is just 10 bytes.
        }
        let result = read_rknot_from_file(&tmp);
        let _ = std::fs::remove_file(&tmp);
        match result {
            Err(ReadError::HeaderTooLong { len, file_size }) => {
                assert_eq!(len, 0xFFFF_FFFF);
                assert_eq!(file_size, 10);
            }
            other => panic!("expected HeaderTooLong, got {:?}", other),
        }
    }

    #[test]
    fn selective_block_load_matches_full_load() {
        // Write our synthetic bytes to a temp file, do the full load and a
        // selective load, compare per-block payloads.
        let (bytes, _header, payloads) = build_synthetic_rknot();
        let tmp =
            std::env::temp_dir().join(format!("rknot_reader_selective_{}.bin", std::process::id()));
        std::fs::write(&tmp, &bytes).unwrap();

        let knot = read_rknot_from_file(&tmp).expect("full load works");

        let mut cursor = Cursor::new(bytes.clone());
        let header = read_rknot_header(&mut cursor).unwrap();
        cursor.seek(SeekFrom::Start(6)).unwrap();
        let mut hlen_buf = [0u8; 4];
        cursor.read_exact(&mut hlen_buf).unwrap();
        let hlen = u32::from_le_bytes(hlen_buf);
        let origin = body_origin(hlen);

        // Selective vs full.
        let q_sel = read_block_payload(&mut cursor, origin, &header.layers[0].q_ref).unwrap();
        let k_sel = read_block_payload(&mut cursor, origin, &header.layers[0].k_ref).unwrap();
        let v_sel = read_block_payload(&mut cursor, origin, &header.layers[0].v_ref).unwrap();
        let ffn_sel = read_block_payload(&mut cursor, origin, &header.layers[0].ffn_ref).unwrap();

        assert_eq!(q_sel, knot.layers[0].q_block.payload);
        assert_eq!(k_sel, knot.layers[0].k_block.payload);
        assert_eq!(v_sel, knot.layers[0].v_block.payload);
        assert_eq!(ffn_sel, knot.layers[0].ffn_block.payload);

        // Sanity: selective payloads also match the originals.
        assert_eq!(q_sel, payloads[0]);
        assert_eq!(k_sel, payloads[1]);
        assert_eq!(v_sel, payloads[2]);
        assert_eq!(ffn_sel, payloads[3]);

        let _ = std::fs::remove_file(&tmp);
    }
}
